#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;

struct qry{int opt,l,r,x;}q[N];//询问

struct Data{int l,r,x;};
 bool operator < (const Data &A , const Data &B){
    return A.r<B.r;
}//重载比较运算符
set<Data> st;//ODT 最主要的 set

struct Node{int l,r;};
 bool operator < (const Node &A , const Node &B){
    return A.r<B.r;
}//重载比较运算符
set<Node> col[N];//每种颜色对应的区间块存放

set<int> cha;//修改存储

struct sol_info{
    int t,id,lst,val;
}so[N*10];//修改信息
int Cnt_sol;//修改信息的个数

int Cnt_time;//时间编号

int n,m,a[N];//基本信息
int pre[N],lst[N],nowpre[N];//pre 数组及求 pre 数组相关

int Lscnt;//离散化后的颜色个数（上限）
map<int,int> Ls;//用于离散化

struct Query{
    int tim,l,r,ans;
}Q[N];//存总询问
int Qcnt;//总询问个数

int pos_[N];//编号暂记

int tr[N];//树状数组

 int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

 void upd(int x,int k){while(x<=n)tr[x]+=k,x+=x&-x;return;}
 int ask(int x){int sum=0;while(x)sum+=tr[x],x-=x&-x;return sum;}
 void clr(int x){while(x<=n)tr[x]=0,x+=x&-x;return;}
//树状数组基本操作

 void change(int id,int color){
   if(nowpre[id]==color)return;
   //已经是了就没有修改这个环节了
   so[++Cnt_sol]={++Cnt_time,id,nowpre[id],-1};//存放撤销操作
   nowpre[id]=color;//修改颜色
   so[++Cnt_sol]={++Cnt_time,id,color,1};//存放增加操作
   return;//修改结束！
}

 void split(int mid){//从 mid 位置切开
    auto it=st.lower_bound({0,mid,0});//找出所在位置
    Data num=*it;//取出其具体值
    if(mid==num.r)return;//处于右端点不用切

    st.erase(num);//删除原值
    st.insert({num.l,mid,num.x});//左半部分
    st.insert({mid+1,num.r,num.x});//右半部分

    col[num.x].erase({num.l,num.r});//删除原值
    col[num.x].insert({num.l,mid});//左半部分
    col[num.x].insert({mid+1,num.r});//右半部分

    return;//切割完毕
}

 void delet(auto it){//删除一个指定位置的迭代器
    Data num=(*it);//取出原值方便后续使用
    cha.insert(num.l);//修改存储

    auto it1=col[num.x].find({num.l,num.r});
    //找出在其对应颜色存储中所在位置
    auto it2=it1;it2++;//复制一份并往后找
    if(it2!=col[num.x].end())cha.insert((*it2).l);//修改存储

    col[num.x].erase(it1);//删除
    st.erase(it);//删除

    return;//删除完毕
}

 void inser(Data num){//插入一个节点
    st.insert(num);//插入集合
    auto it=col[num.x].insert({num.l,num.r}).fr;
    //插入并得到迭代器位置

    ++it;//往后挪一个位置
    if(it!=col[num.x].end())cha.insert((*it).l);//修改存储

    return;//插入完毕
}

 void change_val(int l,int r,int x){
    //区间赋值（即题目中的修改操作）
    if(l!=1)split(l-1);//把左边切开
    split(r);//把右边切开
    //这样就能确保能够完整删去 [l,r] 这一段

    int now=l;//从 l 出发开始跑
    while(now!=r+1){
        auto it=st.lower_bound({0,now,0});
        //找到包含该位置的区间对应迭代器
        now=(*it).r+1;//更新迭代往后走
        delet(it);//删除这个迭代器
    }//彻底删除 [l,r] 这段区间

    inser({l,r,x});//把新的完整区间塞回去

    auto it=cha.begin();//枚举所有被改过的地方
    while(it!=cha.end()){//只要没枚举完
        auto ths=st.lower_bound({0,*it,0});
        //找到对应迭代器
        if(*it!=(*ths).l)change(*it,*it-1);
        //左端点不是自身，直接修改
        else{
            auto ths2=col[(*ths).x].lower_bound({0,*it});
            //在对应颜色里找区间
            if(ths2!=col[(*ths).x].begin())//有前继
                ths2--,change(*it,(*ths2).r);//修改前继
            else change(*it,0);//直接修改当前位置
        }
        it++;
    }cha.clear();//清空

    return;//终于修改完了！
}

 bool cmpQQ(Query q1,Query q2){return q1.l<q2.l;}
//用于给询问操作序列排序的比较函数

 bool cmpPOS(int x,int y){return pre[x]<pre[y];}
//比较函数，对下标按照 pre 的大小从小到大排序

 bool cmpTIME(Query q1,Query q2){return q1.tim<q2.tim;}
//对询问按时间顺序从小到大排序的比较函数

 bool cmpSOL(sol_info s1,sol_info s2){return s1.lst<s2.lst;}
//用于给修改操作序列排序的比较函数

 void CDQsolve(int l1,int r1,int l2,int r2,int L,int R){
    //核心处理的 CDQ 函数
    //注意这里把修改操作 [l1,r1] 和询问操作 [l2,r2] 分开放了
    //这样能很大程度上降低代码复杂性
    if(l1==r1||l2==r2)return;//到头了
    int mid=(L+R)>>1;//求中点
    int mid1=l1;while(mid1<r1&&so[mid1+1].t<=mid)mid1++;
    int mid2=l2;while(mid2<r2&&Q[mid2+1].tim<=mid)mid2++;
    //找到修改序列和询问序列分别的中点
    CDQsolve(l1,mid1,l2,mid2,L,mid);//往左递归
    CDQsolve(mid1,r1,mid2,r2,mid,R);//往右递归
    if(l1==mid1||mid2==r2)return;//到头了
    sort(so+l1+1,so+mid1+1,cmpSOL);
    sort(Q+mid2+1,Q+r2+1,cmpQQ);//分别排序
    for(int i=mid2+1,j=l1+1;i<=r2;i++){//枚举后半截询问
        while(j<=mid1&&so[j].lst<Q[i].l)//在范围内
            upd(so[j].id,so[j].val),j++;//加入树状数组并继续往后查
        Q[i].ans+=ask(Q[i].r)-ask(Q[i].l-1);//更新答案
    }for(int i=l1+1;i<=mid1;i++)clr(so[i].id);//清空树状数组
    return;//CDQ 处理结束！
}

int main(){
    n=read(),m=read();

    for(int i=1;i<=n;i++)
        a[i]=read(),Ls[a[i]]=1;
        //读入并存进 map 稍后离散化

    for(int i=1;i<=m;i++){
        q[i].opt=read(),q[i].l=read(),q[i].r=read();
        if(q[i].opt==1)q[i].x=read(),Ls[q[i].x]=1;
    }//读入询问并将颜色值也存进 map 离散化

    for(auto &u:Ls)u.se=(++Lscnt);
    for(int i=1;i<=n;i++)a[i]=Ls[a[i]];
    for(int i=1;i<=m;i++)
        if(q[i].opt==1)q[i].x=Ls[q[i].x];
    //将颜色值更新为离散化后的值

    for(int i=1;i<=n;i++)
        pre[i]=lst[a[i]],lst[a[i]]=i;
    //递推求出最原始的 pre 数组
    for(int i=1;i<=n;i++)
        nowpre[i]=pre[i];//存储初值

    int tmpcol=a[1],cc=1;//长度
    for(int i=2;i<=n;i++)//枚举每个位置
        if(tmpcol!=a[i])
            st.insert({i-cc,i-1,tmpcol}),//插入大集合
            col[tmpcol].insert({i-cc,i-1}),//插入颜色集合
            tmpcol=a[i],cc=1;//重置维护信息
        else cc++;//个数增加
    st.insert({n-cc+1,n,tmpcol}),//插入大集合
    col[tmpcol].insert({n-cc+1,n});//插入颜色集合

    for(int i=1;i<=m;i++){
        if(q[i].opt==1)change_val(q[i].l,q[i].r,q[i].x);
        //是修改操作就修改，同步维护 ODT 状态
        else Q[++Qcnt]={++Cnt_time,q[i].l,q[i].r,0};
        //是询问操作就记录下来，稍后 CDQ 一起解决
    }


    sort(Q+1,Q+Qcnt+1,cmpQQ);//排序

    for(int i=1;i<=n;i++)pos_[i]=i;//下标存储
    sort(pos_+1,pos_+n+1,cmpPOS);//排序

    for(int i=1,j=1;i<=Qcnt;i++){//枚举每个询问
        while(j<=n&&pre[pos_[j]]<Q[i].l)//如果这个位置还能被计入（pre 位置达标）
            upd(pos_[j],1),j++;//记进树状数组并往后查
        Q[i].ans+=ask(Q[i].r)-ask(Q[i].l-1);//初始答案
    }

    for(int i=0;i<=n;i++)tr[i]=0;//清空树状数组

    sort(Q+1,Q+Qcnt+1,cmpTIME);//按时间顺序排序
    CDQsolve(0,Cnt_sol,0,Qcnt,0,Cnt_time);//CDQ 分治

    sort(Q+1,Q+Qcnt+1,cmpTIME);//按时间顺序排序回来
    for(int i=1;i<=Qcnt;i++)
        cout<<Q[i].ans<<"\n";//输出答案
    return 0;
}
